mapper.select:
SELECT d.document_id, d.student_id, stu.real_name AS student_name, d.topic_id, t.topic_title, d.document_type, d.file_name, d.file_path, d.file_size, d.file_suffix, d.uploader_id, uploader.real_name AS uploader_name, d.version, d.is_latest, d.remark, d.create_time, d.update_time FROM document_info d LEFT JOIN user_info stu ON d.student_id COLLATE utf8mb4_unicode_ci = stu.user_id COLLATE utf8mb4_unicode_ci LEFT JOIN topic_info t ON d.topic_id COLLATE utf8mb4_unicode_ci = t.topic_id COLLATE utf8mb4_unicode_ci LEFT JOIN user_info uploader ON d.uploader_id COLLATE utf8mb4_unicode_ci = uploader.user_id COLLATE utf8mb4_unicode_ci WHERE d.topic_id = #{topicId} AND d.is_deleted = 0
AND d.document_type = #{documentType}
ORDER BY d.document_type ASC, d.version DESC

SELECT COALESCE(MAX(version), 0)
FROM document_info
WHERE student_id = #{studentId}
  AND document_type = #{documentType}
  AND is_deleted = 0

mapper.update:
UPDATE document_info
SET is_latest = 0,
    update_time = NOW()
WHERE student_id = #{studentId}
  AND document_type = #{documentType}
  AND is_deleted = 0

    AND document_id != #{excludeDocId}
